(function(){
  'use strict';
  // ── Гейт: только страница тренинга SYSTEM (Модули) ───────────────────
  if (!/teach\/control\/stream\/view\/id\/935643857/.test(location.href)) return;
  if (window.__sysProg2Init) return; window.__sysProg2Init = true;

  var MAP  = window.SYSTEM_PROGRESS_MAP;      // из map.compact.js — [{name, train, lessons:[{v:[[hash,dur],...]}]}]
  var USER = window.__forceUserId || window.accountUserId;
  var API  = 'https://v02.getcourse.ru/api/save-last-seen-time/get';
  var TH   = 0.9;                              // порог «просмотрено»
  var CKEY = 'sysprog2_' + USER;
  var CTTL = 30 * 60 * 1000;
  var ROWS = ['xdgetr4458','xdgetr7677','xdgetr467'];   // 3 ряда карточек модулей (по 2)

  // ── current_time одного видео (CORS открыт) ──────────────────────────
  var mem = {};
  function ct(hash){
    if (mem[hash] != null) return Promise.resolve(mem[hash]);
    return fetch(API + '?user-id=' + USER + '&video-hash=' + hash + '&tc=' + Date.now())
      .then(function(r){ return r.json(); })
      .then(function(j){ return mem[hash] = (j && j.current_time) || 0; })
      .catch(function(){ return 0; });
  }
  function lessonDone(l){
    if (!l.v || !l.v.length) return Promise.resolve(false);
    return Promise.all(l.v.map(function(v){ return ct(v[0]).then(function(t){ return t >= v[1] * TH; }); }))
      .then(function(a){ return a.every(Boolean); });
  }
  function compute(){
    return Promise.all(MAP.map(function(mod){
      var wv = (mod.lessons || []).filter(function(l){ return l.v && l.v.length; });
      return Promise.all(wv.map(lessonDone)).then(function(res){
        return { name: mod.name, train: mod.train, total: wv.length, done: res.filter(Boolean).length };
      });
    }));
  }
  function fromCache(){ try { var c = JSON.parse(localStorage.getItem(CKEY)); if (c && Date.now()-c.ts < CTTL) return c.data; } catch(e){} return null; }
  function toCache(d){ try { localStorage.setItem(CKEY, JSON.stringify({ ts: Date.now(), data: d })); } catch(e){} }

  // ── Контейнеры карточек модулей (первые MAP.length с картинкой) ──────
  function moduleContainers(){
    var conts = [];
    ROWS.forEach(function(id){
      var r = document.getElementById(id);
      if (r) [].slice.call(r.children).forEach(function(c){
        if (c.classList && c.classList.contains('xdget-container') && c.querySelector('img')) conts.push(c);
      });
    });
    return conts.slice(0, MAP.length);
  }

  // ── Оверлей поверх белого окошка баннера ─────────────────────────────
  function overlay(cont, st){
    var wrap = cont.querySelector('.xdget-image'); if (!wrap) return;
    wrap.style.position = 'relative';
    var old = wrap.querySelector('.sp2ov'); if (old) old.remove();
    var ov = document.createElement('div'); ov.className = 'sp2ov';
    ov.style.cssText = 'position:absolute;inset:0;pointer-events:none;font-family:Manrope,-apple-system,sans-serif';
    var link = '/pl/teach/control/stream/view/id/' + st.train;
    if (!st.total){
      ov.innerHTML =
        '<div style="position:absolute;left:9%;right:9%;top:63.5%;bottom:6%;display:flex;flex-direction:column;justify-content:center;align-items:center;gap:6px;pointer-events:auto">' +
        '<div style="font-size:15px;font-weight:800;color:#111;opacity:.45">Скоро</div>' +
        '<div style="font-size:11px;font-weight:600;color:#111;opacity:.4">Уроки готовятся</div></div>';
      wrap.appendChild(ov); return;
    }
    var pct = Math.round(st.done / st.total * 100), R = 18, C = 2*Math.PI*R, off = C*(1-pct/100);
    ov.innerHTML =
     '<div style="position:absolute;left:9%;right:9%;top:63.5%;bottom:6%;display:flex;flex-direction:column;justify-content:center;gap:15px;pointer-events:auto">' +
       '<div style="display:flex;align-items:center;gap:12px">' +
         '<div style="flex:1;height:9px;border-radius:6px;background:rgba(0,0,0,.12);overflow:hidden">' +
           '<div style="height:100%;width:'+pct+'%;background:#111;border-radius:6px"></div></div>' +
         '<div style="font-size:15px;font-weight:800;color:#111">'+pct+'%</div>' +
       '</div>' +
       '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px">' +
         '<div style="display:flex;align-items:center;gap:11px">' +
           '<svg width="44" height="44" viewBox="0 0 44 44" style="flex:0 0 auto">' +
             '<circle cx="22" cy="22" r="'+R+'" fill="none" stroke="rgba(0,0,0,.13)" stroke-width="5"/>' +
             '<circle cx="22" cy="22" r="'+R+'" fill="none" stroke="#111" stroke-width="5" stroke-linecap="round" ' +
               'stroke-dasharray="'+C+'" stroke-dashoffset="'+off+'" transform="rotate(-90 22 22)"/></svg>' +
           '<div style="line-height:1.15">' +
             '<div style="font-size:16px;font-weight:800;color:#111">'+st.done+' / '+st.total+'</div>' +
             '<div style="font-size:11px;font-weight:600;color:#111;opacity:.6">Уроков пройдено</div></div>' +
         '</div>' +
         '<a href="'+link+'" style="display:inline-block;background:#111!important;color:#fff!important;text-decoration:none!important;font-weight:700;font-size:14px;padding:12px 26px;border-radius:11px;white-space:nowrap;border:none">Изучить</a>' +
       '</div>' +
     '</div>';
    wrap.appendChild(ov);
  }

  function render(stats){
    moduleContainers().forEach(function(cont, i){
      var mod = MAP[i]; if (!mod) return;
      var st = stats.filter(function(s){ return s.name === mod.name; })[0] || { name:mod.name, train:mod.train, total:0, done:0 };
      overlay(cont, st);
    });
  }

  function boot(){
    if (!MAP || !USER) return;
    var c = fromCache(); if (c) render(c);
    compute().then(function(stats){ toCache(stats); render(stats); });
  }
  var tries = 0;
  (function wait(){
    if (document.getElementById(ROWS[0]) && document.getElementById(ROWS[0]).querySelector('.xdget-image img')) return boot();
    if (tries++ < 40) setTimeout(wait, 250);
  })();
})();
